import{_ as r,C as i,o as t,c as n,a2 as E,E as o,j as e,a as A}from"./chunks/framework.DnrXFDHb.js";const f=JSON.parse('{"title":"Workflow 笔记：状态和事件比图更重要","description":"","frontmatter":{},"headers":[],"relativePath":"agent/workflow-notes.md","filePath":"agent/workflow-notes.md","lastUpdated":1782828436000}'),p={name:"agent/workflow-notes.md"};function B(s,a,h,d,D,u){const l=i("Mermaid");return t(),n("div",null,[a[0]||(a[0]=E('<h1 id="workflow-笔记-状态和事件比图更重要" tabindex="-1">Workflow 笔记：状态和事件比图更重要 <a class="header-anchor" href="#workflow-笔记-状态和事件比图更重要" aria-label="Permalink to &quot;Workflow 笔记：状态和事件比图更重要&quot;">​</a></h1><p>做 Agent 工作流时，我一开始很想上 Graph。模型调用是节点，工具执行是节点，人工输入是节点，远端能力也是节点。节点之间用条件边连接，听起来很自然。</p><p>后来发现，Graph 不是第一步。真正的第一步是状态和事件：任务现在在哪，历史发生过什么，失败后能不能恢复。</p><h2 id="为什么没有一开始做通用-graph" tabindex="-1">为什么没有一开始做通用 Graph <a class="header-anchor" href="#为什么没有一开始做通用-graph" aria-label="Permalink to &quot;为什么没有一开始做通用 Graph&quot;">​</a></h2><p>通用 Graph 在白板上很好看。可一落地，每个节点都会追问：</p><ul><li>节点状态存在哪里？</li><li>节点失败能不能重试？</li><li>重试会不会重复执行工具？</li><li>用户取消怎么传播？</li><li>等待用户输入后怎么恢复？</li><li>前端刷新后怎么还原运行过程？</li></ul><p>如果这些问题没有答案，Graph 只是更复杂的内存调度。</p><p>我后来选择先做三件更基础的事。</p>',8)),o(l,{code:"flowchart%20LR%0A%20%20%20%20State%5B%22%E7%8A%B6%E6%80%81%E6%9C%BA%3Cbr%2F%3E%E7%9F%A5%E9%81%93%E5%BD%93%E5%89%8D%E5%9C%A8%E5%93%AA%22%5D%20--%3E%20Runtime%5B%22%E6%89%A7%E8%A1%8C%E8%BF%87%E7%A8%8B%22%5D%0A%20%20%20%20Event%5B%22%E4%BA%8B%E4%BB%B6%E6%97%A5%E5%BF%97%3Cbr%2F%3E%E7%9F%A5%E9%81%93%E5%8F%91%E7%94%9F%E8%BF%87%E4%BB%80%E4%B9%88%22%5D%20--%3E%20Projection%5B%22%E5%89%8D%E7%AB%AF%E6%8A%95%E5%BD%B1%20%2F%20%E5%8E%86%E5%8F%B2%E6%81%A2%E5%A4%8D%22%5D%0A%20%20%20%20Reaper%5B%22%E6%94%B6%E6%95%9B%E6%9C%BA%E5%88%B6%3Cbr%2F%3E%E5%A4%84%E7%90%86%E8%B6%85%E6%97%B6%E5%92%8C%E5%BC%82%E5%B8%B8%E4%B8%AD%E6%96%AD%22%5D%20--%3E%20Runtime%0A%20%20%20%20Runtime%20--%3E%20Event%0A%20%20%20%20Runtime%20--%3E%20State%0A"}),a[1]||(a[1]=e("p",null,"状态机定义任务阶段。事件日志记录真实发生的动作。收敛机制处理长期不结束或执行方异常退出的任务。",-1)),a[2]||(a[2]=e("p",null,"这三件事不炫，但很重要。",-1)),a[3]||(a[3]=e("h2",{id:"工作流里的三条线",tabindex:"-1"},[A("工作流里的三条线 "),e("a",{class:"header-anchor",href:"#工作流里的三条线","aria-label":'Permalink to "工作流里的三条线"'},"​")],-1)),o(l,{code:"flowchart%20TB%0A%20%20%20%20subgraph%20S%5B%22%E7%8A%B6%E6%80%81%E7%BA%BF%22%5D%0A%20%20%20%20%20%20%20%20S1%5B%22Pending%22%5D%20--%3E%20S2%5B%22Building%22%5D%0A%20%20%20%20%20%20%20%20S2%20--%3E%20S3%5B%22Calling%22%5D%0A%20%20%20%20%20%20%20%20S3%20--%3E%20S4%5B%22Executing%22%5D%0A%20%20%20%20%20%20%20%20S4%20--%3E%20S5%5B%22Waiting%20Input%22%5D%0A%20%20%20%20%20%20%20%20S5%20--%3E%20S2%0A%20%20%20%20%20%20%20%20S4%20--%3E%20S6%5B%22Terminal%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20E%5B%22%E4%BA%8B%E4%BB%B6%E7%BA%BF%22%5D%0A%20%20%20%20%20%20%20%20E1%5B%22User%20Message%22%5D%20--%3E%20E2%5B%22Model%20Delta%22%5D%0A%20%20%20%20%20%20%20%20E2%20--%3E%20E3%5B%22Tool%20Call%22%5D%0A%20%20%20%20%20%20%20%20E3%20--%3E%20E4%5B%22Tool%20Result%22%5D%0A%20%20%20%20%20%20%20%20E4%20--%3E%20E5%5B%22State%20Delta%22%5D%0A%20%20%20%20%20%20%20%20E5%20--%3E%20E6%5B%22Run%20Finished%22%5D%0A%20%20%20%20end%0A%0A%20%20%20%20subgraph%20D%5B%22%E5%86%B3%E7%AD%96%E7%BA%BF%22%5D%0A%20%20%20%20%20%20%20%20D1%5B%22%E6%A8%A1%E5%9E%8B%E8%BE%93%E5%87%BA%22%5D%20--%3E%20D2%5B%22%E7%AD%96%E7%95%A5%E5%88%A4%E6%96%AD%22%5D%0A%20%20%20%20%20%20%20%20D2%20--%3E%20D3%5B%22%E7%BB%A7%E7%BB%AD%20%2F%20%E7%AD%89%E5%BE%85%20%2F%20%E5%81%9C%E6%AD%A2%22%5D%0A%20%20%20%20end%0A"}),a[4]||(a[4]=E('<p>状态线回答“现在在哪”。事件线回答“发生过什么”。决策线回答“为什么往这条路走”。</p><p>Agent 的真实执行往往不是静态 DAG，而是循环、等待、恢复、取消混在一起。强行一开始画成完整图，容易让模型执行的复杂度隐藏在节点里。</p><h2 id="graph-什么时候值得做" tabindex="-1">Graph 什么时候值得做 <a class="header-anchor" href="#graph-什么时候值得做" aria-label="Permalink to &quot;Graph 什么时候值得做&quot;">​</a></h2><p>我不是反对 Graph。只是觉得它应该建立在状态和事件之上。</p><p>当任务开始出现这些需求时，Graph 就有价值：</p><ul><li>明确的多阶段任务。</li><li>并行分支和条件合并。</li><li>可复用的人工审批节点。</li><li>子任务重试和超时策略。</li><li>长周期计划执行。</li><li>多 Agent 子任务树。</li></ul><p>但 Graph Runtime 不应该另起事实源。节点执行结果仍然要写事件，人工输入仍然是状态，工具执行仍然要幂等。</p><h2 id="踩过的坑" tabindex="-1">踩过的坑 <a class="header-anchor" href="#踩过的坑" aria-label="Permalink to &quot;踩过的坑&quot;">​</a></h2><p>第一个坑，是把工作流等同于图。其实状态机加事件日志已经能覆盖很多 Agent 场景。</p><p>第二个坑，是只存当前状态。状态告诉你现在是什么，但解释不了为什么变成这样。</p><p>第三个坑，是只存事件但不做投影。事件能恢复历史，但前端需要当前视图。</p><p>第四个坑，是 Human In Loop 不进状态机。人工输入必须是执行状态，不是 UI 装饰。</p><h2 id="现在的记录" tabindex="-1">现在的记录 <a class="header-anchor" href="#现在的记录" aria-label="Permalink to &quot;现在的记录&quot;">​</a></h2><p>如果再做一次，我会按这个顺序来：</p><ol><li>先做状态机和事件事实源。</li><li>再抽象常见节点：模型调用、工具执行、人工输入、沙箱任务。</li><li>最后做轻量 Graph，用来表达确实需要结构化编排的场景。</li></ol><p>一句话总结：工作流不是从画节点开始的，而是从任务失败后还能不能还原现场开始的。</p><h2 id="podcast-提纲" tabindex="-1">Podcast 提纲 <a class="header-anchor" href="#podcast-提纲" aria-label="Permalink to &quot;Podcast 提纲&quot;">​</a></h2><ol><li>为什么我没有一开始做通用 Graph。</li><li>状态机、事件日志、Graph 分别解决什么。</li><li>Agent Loop 和 Workflow 的关系。</li><li>Human In Loop 为什么必须进入状态。</li><li>Graph 绕开事实源会带来什么问题。</li><li>什么时候真的需要图执行。</li><li>如何从状态机自然演进到 Graph。</li></ol>',18))])}const _=r(p,[["render",B]]);export{f as __pageData,_ as default};
